import{_ as e,o as r,c as n,ai as t}from"./chunks/framework.CaiDwmc7.js";const u=JSON.parse('{"title":"Spring 常见高频问题与坑点","description":"","frontmatter":{},"headers":[],"relativePath":"framework/spring-faq.md","filePath":"framework/spring-faq.md"}'),i={name:"framework/spring-faq.md"};function s(g,o,l,a,c,d){return r(),n("div",null,[...o[0]||(o[0]=[t('<h1 id="spring-常见高频问题与坑点" tabindex="-1">Spring 常见高频问题与坑点 <a class="header-anchor" href="#spring-常见高频问题与坑点" aria-label="Permalink to “Spring 常见高频问题与坑点”">​</a></h1><hr><h3 id="❓-面试官-spring-框架是怎么解决循环依赖问题的" tabindex="-1">❓ 面试官：Spring 框架是怎么解决循环依赖问题的？ <a class="header-anchor" href="#❓-面试官-spring-框架是怎么解决循环依赖问题的" aria-label="Permalink to “❓ 面试官：Spring 框架是怎么解决循环依赖问题的？”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> Spring 只能解决<strong>单例模式（Singleton）</strong>下的<strong>属性注入（或 Setter 注入）</strong>导致的循环依赖。它的核心底层机制是 <strong>“三级缓存”</strong>。如果遇到<strong>构造器注入</strong>或者<strong>原型模式（Prototype）</strong>的循环依赖，Spring 依然会直接报错抛出异常。</p><p><strong>📝 详细原理解析（三级缓存是什么？）：</strong> 假设 <code>A</code> 依赖 <code>B</code>，<code>B</code> 又依赖 <code>A</code>。</p><ol><li><strong>第一级缓存（singletonObjects）</strong>：存放完全初始化好的成品的 Bean（我们日常 <code>getBean</code> 拿到的就是它）。</li><li><strong>第二级缓存（earlySingletonObjects）</strong>：存放<strong>半成品</strong>的 Bean（已经实例化，但还没进行属性注入）。</li><li><strong>第三级缓存（singletonFactories）</strong>：存放可以生成半成品 Bean 的<strong>工厂（Factory / Lambda 表达式）</strong>。</li></ol><p><strong>经典推演流程（破局之道：提前暴露半成品）：</strong></p><ul><li>实例化 A（<code>new A()</code>），此时 A 是个空壳子（半成品）。</li><li>Spring 把 A 包装进一个<strong>对象工厂（第三级缓存）</strong>里提前暴露出去。</li><li>A 开始属性注入，发现自己需要 B。此时去单例池找，没找到 B。</li><li>Spring 转头去实例化 B（<code>new B()</code>），同样是个空壳子。</li><li>B 开始属性注入，发现自己需要 A。</li><li>B 去找 A，发现在一二级缓存都没有，最终在<strong>第三级缓存</strong>里找到了 A 的工厂。</li><li>B 通过执行该工厂方法，把 A 的早期引用提前拿了出来，放入<strong>第二级缓存</strong>。此时 B 成功拿到了“还没完全装配好的 A”，完成了属性注入。</li><li>B 完成所有初始化，变成成品，放入<strong>第一级缓存</strong>。</li><li>回到 A 的注入过程，此时 A 发现 B 已经在第一级缓存里了，直接拿到成品 B 注入。</li><li>A 也完成初始化，放入第一级缓存，完美闭环！</li></ul><p><strong>🌟 面试加分项（为什么非要三级？二级不行吗？）：</strong> &quot;其实如果只是普通的循环依赖，二级缓存就足够破局了（提前暴露半成品）。之所以必须用三级缓存（对象工厂），完全是为了<strong>处理 AOP（代理对象）</strong>。 如果 A 被切面代理了，最终放进单例池的应该是 A 的代理对象，而不是原生 A。 但 AOP 代理逻辑通常是在 Bean 生命周期的最后一步（初始化后）才执行的。如果在循环依赖中，B 提前要用 A，这时候 B 拿到的是原生 A。等 A 最后自己走完 AOP 变成了代理对象，这就乱套了。 所以三级缓存的工厂方法起到了一个兜底作用：如果有 AOP，该工厂会在 B 需要 A 的时候，<strong>立刻、提前去执行代理生成逻辑</strong>，把 A 的代理对象提前造出来返回给 B。这样就保证了单例的绝对一致性。&quot;</p><hr><h3 id="❓-面试官-如果我必须用构造器注入-又发生了循环依赖-该怎么解决-【中级】" tabindex="-1">❓ 面试官：如果我必须用构造器注入，又发生了循环依赖，该怎么解决？【中级】 <a class="header-anchor" href="#❓-面试官-如果我必须用构造器注入-又发生了循环依赖-该怎么解决-【中级】" aria-label="Permalink to “❓ 面试官：如果我必须用构造器注入，又发生了循环依赖，该怎么解决？【中级】”">​</a></h3><p><em>频率：🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 因为构造器注入在 <code>new</code> 对象的那一瞬间就需要所有依赖，所以 Spring 的“提前暴露半成品”机制完全失效（连半壳子都没造出来）。解决办法通常是：<strong>重构代码解耦</strong> 或者 使用 <strong><code>@Lazy</code> 注解</strong>。</p><p><strong>📝 详细解决方案：</strong></p><ol><li><strong>方案一（官方推荐）：重构设计</strong><ul><li>出现循环依赖通常意味着设计不合理（比如订单 Service 和支付 Service 强耦合）。应该抽出一个公共的、不依赖这俩类的第三方 Service。</li></ul></li><li><strong>方案二：打上 <code>@Lazy</code> 注解</strong><ul><li>做法：在其中一个类的构造器参数上加上 <code>@Lazy</code>（比如在 A 依赖 B 的时候：<code>public A(@Lazy B b)</code>）。</li><li>原理：加上 <code>@Lazy</code> 后，Spring 在给 A 注入 B 的时候，并不会立刻去真实创建 B，而是<strong>塞给 A 一个基于 CGLib 生成的 B 的代理对象</strong>。等 A 在以后真正调用 <code>b.doSomething()</code> 时，这个代理对象才会去触发真实的 B 的实例化。通过这种“拖延战术”完美避开了启动时的死结。</li></ul></li></ol><hr><h3 id="❓-面试官-spring-里的-autowired-和-resource-有什么区别" tabindex="-1">❓ 面试官：Spring 里的 <code>@Autowired</code> 和 <code>@Resource</code> 有什么区别？ <a class="header-anchor" href="#❓-面试官-spring-里的-autowired-和-resource-有什么区别" aria-label="Permalink to “❓ 面试官：Spring 里的 @Autowired 和 @Resource 有什么区别？”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong></p><ul><li><strong><code>@Autowired</code></strong> 是 <strong>Spring</strong> 官方自己提供的注解；它默认按<strong>类型（byType）</strong>去匹配寻找 Bean。</li><li><strong><code>@Resource</code></strong> 是 <strong>JDK/J2EE（JSR-250 规范）</strong> 提供的注解；它默认按<strong>名称（byName）</strong>去匹配寻找 Bean。</li></ul><p><strong>📝 详细原理解析（坑点）：</strong></p><ol><li><strong><code>@Autowired</code> 的寻找逻辑</strong>： <ul><li>先根据类型去找。如果容器里只有一个该类型的实现类，直接注入成功。</li><li>如果发现容器里有两个该类型的实现类（比如接口 <code>PaymentService</code> 有 <code>AliPay</code> 和 <code>WechatPay</code> 两个实现类），它就会降级，转而根据<strong>你的变量名</strong>去匹配。如果你变量名叫 <code>aliPay</code>，且刚好有个 Bean 的名字也是 <code>aliPay</code>，就注入成功；如果不匹配，直接抛异常。</li><li>解决方案：通常配合 <strong><code>@Qualifier(&quot;beanName&quot;)</code></strong> 一起使用，强制指定 Bean 名字。</li></ul></li><li><strong><code>@Resource</code> 的寻找逻辑</strong>： <ul><li>如果你在注解里写了 <code>@Resource(name = &quot;aliPay&quot;)</code>，就绝对按这个名字找，找不到就报错。</li><li>如果你什么都不写，它先根据<strong>变量名</strong>当做 Bean 名字去找；如果变量名找不到，它就降级，按<strong>类型</strong>去找。</li></ul></li></ol><p><strong>结论</strong>：在实际开发中，如果只有一个实现类，用哪个都行；如果有多个实现类，推荐使用 <code>@Resource(name=&quot;xxx&quot;)</code>，比写两个注解（<code>@Autowired + @Qualifier</code>）更简洁。</p>',24)])])}const A=e(i,[["render",s]]);export{u as __pageData,A as default};
